Class Healthcare.PatientService Extends %RegisteredObject
{
    /// Get patient's full name
    ClassMethod GetPatientName(patientId As %String) As %String
    {
        Set patient = ##class(Healthcare.Patient).%OpenId(patientId)

        // BUGGY: No null check - causes <OBJECT REFERENCE> error if patient doesn't exist
        Set fullName = patient.FirstName _ " " _ patient.LastName

        Quit fullName
    }
}

Class Healthcare.Patient Extends %Persistent
{
    Property FirstName As %String;

    Property LastName As %String;
}

