Class TestPatientService Extends %RegisteredObject
{
    ClassMethod TestGetPatientName()
    {
        // Test with valid patient
        Set patient = ##class(Healthcare.Patient).%New()
        Set patient.FirstName = "John"
        Set patient.LastName = "Doe"
        Set sc = patient.%Save()
        If $$$ISERR(sc) { Throw ##class(%Exception.General).%New("Patient should save successfully") }

        Set id = patient.%Id()
        Set name = ##class(Healthcare.PatientService).GetPatientName(id)
        If (name) '= ("John Doe") { Throw ##class(%Exception.General).%New("Should return full name") }

        // Test with invalid patient ID (should not crash)
        Set name = ##class(Healthcare.PatientService).GetPatientName("999999")
        If (name) '= ("") { Throw ##class(%Exception.General).%New("Should return empty string for non-existent patient") }
    }
}
